SET search_path TO bank_r2_003;
CREATE TABLE accounts (account_id integer PRIMARY KEY, account_name text NOT NULL, currency text NOT NULL CHECK (currency IN ('GBP','USD')));
CREATE TABLE ledger_transactions (ledger_transaction_id integer PRIMARY KEY, state text NOT NULL CHECK (state IN ('pending','posted','reversed','failed')), currency text NOT NULL CHECK (currency IN ('GBP','USD')));
CREATE TABLE ledger_entries (ledger_entry_id integer PRIMARY KEY, ledger_transaction_id integer NOT NULL REFERENCES ledger_transactions(ledger_transaction_id), account_id integer NOT NULL REFERENCES accounts(account_id), side text NOT NULL CHECK (side IN ('debit','credit')), amount_cents integer NOT NULL CHECK (amount_cents > 0));
CREATE TABLE transfer_requests (transfer_id integer PRIMARY KEY, from_account_id integer NOT NULL REFERENCES accounts(account_id), to_account_id integer NOT NULL REFERENCES accounts(account_id), amount_cents integer NOT NULL CHECK (amount_cents > 0), currency text NOT NULL CHECK (currency IN ('GBP','USD')), request_state text NOT NULL CHECK (request_state IN ('created','posted','failed','conflict')), ledger_transaction_id integer REFERENCES ledger_transactions(ledger_transaction_id));
CREATE TABLE idempotency_keys (key_id integer PRIMARY KEY, idempotency_key text NOT NULL UNIQUE, request_fingerprint text NOT NULL, transfer_id integer REFERENCES transfer_requests(transfer_id), key_state text NOT NULL CHECK (key_state IN ('active','failed','conflict')));
CREATE TABLE transfer_attempts (attempt_id integer PRIMARY KEY, idempotency_key text NOT NULL, request_fingerprint text NOT NULL, attempt_state text NOT NULL CHECK (attempt_state IN ('created','duplicate_returned','conflict','failed_retryable')), transfer_id integer REFERENCES transfer_requests(transfer_id), attempted_at timestamp NOT NULL);
